.year-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 12px;
}
@media (max-width: 1100px) { .year-grid { grid-template-columns: repeat(3, 1fr); } }
@media (max-width: 768px)  { .year-grid { grid-template-columns: repeat(2, 1fr); } }
@media (max-width: 480px)  { .year-grid { grid-template-columns: 1fr; } }

.mini-month {
    background: #fff;
    border-radius: 10px;
    border: 1px solid #e5e7eb;
    overflow: hidden;
    box-shadow: 0 1px 4px rgba(0,0,0,.05);
}
.mini-month-header {
    background: #4f46e5;
    color: #fff;
    text-align: center;
    padding: 7px 10px;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: .3px;
    cursor: pointer;
}
.mini-month-header:hover { background: #4338ca; }
.mini-cal-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    padding: 4px 6px 6px;
    gap: 1px;
}
.mini-dow {
    text-align: center;
    font-size: 9px;
    color: #9ca3af;
    font-weight: 600;
    padding: 3px 0;
    text-transform: uppercase;
}
.mini-day-cell {
    text-align: center;
    font-size: 11px;
    padding: 2px 1px;
    border-radius: 50%;
    cursor: pointer;
    position: relative;
    min-height: 24px;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: flex-start;
    transition: background .1s;
}
.mini-day-cell:hover { background: #f3f4f6; }
.mini-day-cell.other-month { color: #d1d5db; }
.mini-day-cell.is-today {
    background: #4f46e5;
    color: #fff;
    border-radius: 50%;
    font-weight: 700;
}
.mini-day-cell.is-today:hover { background: #4338ca; }
.mini-day-cell.is-weekend { color: #6b7280; }
.mini-day-cell.is-holiday > .day-num { color: #ef4444; font-weight: 700; }
.day-num { line-height: 1.4; }
.day-dots {
    display: flex;
    gap: 2px;
    justify-content: center;
    flex-wrap: wrap;
    margin-top: 1px;
}
.day-dot {
    width: 5px;
    height: 5px;
    border-radius: 50%;
    flex-shrink: 0;
}
/* Eth sub-label */
.eth-sub { font-size: 8px; color: #c4b5fd; display: block; line-height: 1; }
/* Legend active */
.legend-item.active { background: #f3f4f6; }
</style>

