    // Correct JDN-based Ethiopian calendar conversion
    function gToJdn(y,m,d){
        var a=Math.floor((14-m)/12), y2=y+4800-a, m2=m+12*a-3;
        return d+Math.floor((153*m2+2)/5)+365*y2+Math.floor(y2/4)-Math.floor(y2/100)+Math.floor(y2/400)-32045;
    }
    function jdnToEth(jdn){
        // Ethiopian epoch JDN = 1724221 (Meskerem 1, 1 E.C. = Aug 29, 8 AD Julian)
        var r = (jdn - 1724221) % 1461;
        if (r < 0) r += 1461;
        var n = r % 365 + 365 * Math.floor(r / 1460);
        var year  = 4 * Math.floor((jdn - 1724221) / 1461) + Math.floor(r / 365) - Math.floor(r / 1460);
        var month = Math.floor(n / 30) + 1;
        var day   = n % 30 + 1;
        return { year: year, month: month, day: day };
    }
    function toEth(y,m,d){ return jdnToEth(gToJdn(y,m,d)); }

