    function switchToFCView(view, date) {
        currentView = view;
        $('#year-view').hide();
        $('#fc-view').show();
        $('.btn-group .btn').removeClass('active btn-primary').addClass('btn-outline-primary');
        $('#view-'+view).removeClass('btn-outline-primary').addClass('btn-primary active');

        if (!fcInitialised) {
            initFullCalendar();
            fcInitialised = true;
        }
        if (date) $('#eth-calendar').fullCalendar('gotoDate', date);
        $('#eth-calendar').fullCalendar('changeView', view === 'week' ? 'agendaWeek' : view === 'agenda' ? 'listYear' : 'month');
    }

    function switchToYearView() {
        currentView = 'year';
        $('#fc-view').hide();
        $('#year-view').show();
        $('.btn-group .btn').removeClass('active btn-primary').addClass('btn-outline-primary');
        $('#view-year').removeClass('btn-outline-primary').addClass('btn-primary active');
        loadYear(currentYear);
    }

    $('#view-year').on('click', switchToYearView);
    $('#view-month').on('click', function(){ switchToFCView('month'); });
    $('#view-week').on('click', function(){ switchToFCView('week'); });
    $('#view-agenda').on('click', function(){ switchToFCView('agenda'); });

