    function initFullCalendar() {
        $('#eth-calendar').fullCalendar({
            header: { left:'prev,next today', center:'title', right:'' },
            height: 'auto',
            editable: canEdit,
            selectable: canEdit,
            eventLimit: 4,
            eventSources: [{
                url: eventsUrl, type: 'GET',
                error: function(){ flash({msg:'Failed to load events.',type:'danger'}); }
            }],
            dayRender: function(date, cell) {
                var eth = toEth(date.year(), date.month()+1, date.date());
                $('<span>').text(eth.day+' '+ethShort[eth.month-1])
                    .css({fontSize:'8px',color:'#c4b5fd',display:'block',textAlign:'right',paddingRight:'3px',lineHeight:'1.2'})
                    .appendTo(cell);
            },
            select: function(start) {
                if (!canEdit) return;
                resetForm();
                $('#ev-start').val(start.format('YYYY-MM-DD'));
                $('#ev-end').val(start.format('YYYY-MM-DD'));
                $('#form-modal-title').text('Add Event');
                $('#form-modal').modal('show');
            },
            eventClick: function(event) {
                currentEventId = event.id;
                currentFCEvent = event;
                var p = event.extendedProps || {};
                var eObj = {
                    id: event.id,
                    title: event.title,
                    start: event.start.format('YYYY-MM-DD'),
                    end: event.end ? event.end.format('YYYY-MM-DD') : null,
                    backgroundColor: event.backgroundColor,
                    extendedProps: p
                };
                $('#btn-add-to-gcal').show();
                showEventModal(eObj);
            },
            eventDrop: function(event) {
                if (String(event.id).startsWith('hol_')) { $('#eth-calendar').fullCalendar('rerenderEvents'); return; }
                var dbId = ((event.extendedProps||{}).dbId) || event.id.replace('ev_','');
                $.post(updateBase+'/'+dbId+'/update', {
                    _token: $('meta[name="csrf-token"]').attr('content'),
                    title: event.title, start_date: event.start.format('YYYY-MM-DD'),
                    end_date: event.end ? event.end.clone().subtract(1,'day').format('YYYY-MM-DD') : null,
                    color: event.backgroundColor, type: (event.extendedProps||{}).type||'event', all_day:1
                }).done(function(){ flash({msg:'Event moved.',type:'success'}); })
                .fail(function(){ $('#eth-calendar').fullCalendar('rerenderEvents'); });
            }
        });
    }

