    function loadUpcoming(events) {
        var today  = new Date().toISOString().split('T')[0];
        var future = new Date(Date.now()+60*24*60*60*1000).toISOString().split('T')[0];

        var src = events
            ? events.filter(function(e){ return e.start >= today && e.start <= future; })
            : null;

        function render(evs) {
            var filtered = activeFilter === 'all' ? evs
                : evs.filter(function(e){ return (e.extendedProps||{}).type === activeFilter; });
            filtered.sort(function(a,b){ return a.start > b.start ? 1 : -1; });
            $('#upcoming-count').text(filtered.length);
            var $ul = $('#upcoming-events').empty();
            if (!filtered.length) { $ul.html('<div class="text-center text-muted py-3" style="font-size:12px;">No upcoming events</div>'); return; }
            filtered.slice(0,15).forEach(function(e) {
                var d = new Date(e.start.split('T')[0]+'T00:00:00');
                var eth = toEth(d.getFullYear(), d.getMonth()+1, d.getDate());
                var daysLeft = Math.ceil((d - new Date().setHours(0,0,0,0))/86400000);
                var badge = daysLeft===0 ? '<span class="badge badge-danger" style="font-size:9px;">Today</span>'
                          : daysLeft===1 ? '<span class="badge badge-warning" style="font-size:9px;">Tomorrow</span>'
                          : '<span style="font-size:10px;color:#9ca3af;">'+daysLeft+'d</span>';
                $ul.append(
                    '<div class="d-flex align-items-start px-2 py-2 border-bottom" style="gap:7px;cursor:pointer;" onclick="window._upcomingClick(\''+e.id+'\')">'
                    +'<div style="width:3px;border-radius:2px;background:'+e.backgroundColor+';align-self:stretch;flex-shrink:0;min-height:32px;"></div>'
                    +'<div style="min-width:0;flex:1;">'
                    +'<div style="font-size:11px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'+e.title+'</div>'
                    +'<div style="font-size:10px;color:#6b7280;">'+d.toLocaleDateString('en-US',{month:'short',day:'numeric'})+' &bull; '+eth.day+' '+ethShort[eth.month-1]+' E.C.</div>'
                    +'</div><div style="flex-shrink:0;">'+badge+'</div></div>'
                );
            });
        }

        if (src) { render(src); return; }
        $.getJSON(eventsUrl, {start:today, end:future}, render);
    }

    window._upcomingClick = function(id) {
        var ev = allEvents.find(function(e){ return e.id == id; });
        if (ev) showEventModal(ev);
    };

