    $('#btn-edit-event').on('click', function() {
        var e = allEvents.find(function(x){ return x.id == currentEventId; });
        if (!e) return;
        var p = e.extendedProps || {};
        resetForm();
        $('#event-id').val(p.dbId || String(e.id).replace('ev_',''));
        $('#ev-title').val(e.title);
        $('#ev-type').val(p.type || 'event');
        $('#ev-start').val(e.start.split('T')[0]);
        $('#ev-end').val(e.end ? new Date(new Date(e.end+'T00:00:00').getTime()-86400000).toISOString().split('T')[0] : '');
        $('#ev-desc').val(p.description || '');
        var c = e.backgroundColor || '#4f46e5';
        $('input[name="ev-color"][value="'+c+'"]').prop('checked',true).closest('label').find('.ev-color-swatch').css('border-color','#1f2937');
        $('#form-modal-title').text('Edit Event');
        $('#event-modal').modal('hide');
        setTimeout(function(){ $('#form-modal').modal('show'); }, 300);
    });

