    $('#btn-delete-event').on('click', function() {
        var e = allEvents.find(function(x){ return x.id == currentEventId; });
        var dbId = e ? ((e.extendedProps||{}).dbId || String(e.id).replace('ev_','')) : String(currentEventId).replace('ev_','');
        swal({title:'Delete Event?',text:'This cannot be undone.',icon:'warning',buttons:true,dangerMode:true})
        .then(function(ok) {
            if (!ok) return;
            $.post(updateBase+'/'+dbId+'/delete', {_token:$('meta[name="csrf-token"]').attr('content')})
            .done(function() {
                allEvents = allEvents.filter(function(x){ return x.id != currentEventId; });
                $('#event-modal').modal('hide');
                renderYearView(currentYear, allEvents);
                loadUpcoming(allEvents.filter(function(e){ return e.start >= new Date().toISOString().split('T')[0]; }));
                if (fcInitialised) $('#eth-calendar').fullCalendar('removeEvents', currentEventId);
                flash({msg:'Event deleted.',type:'success'});
            });
        });
    });

